import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();

        out.println("<html>");
        out.println("<head><title>Secure Page</title></head>");
        out.println("<body>");

        // Sanitize and escape user input before outputting it
        out.println("<h1>User Input: " + escapeHtml(userInput) + "</h1>");

        out.println("</body>");
        out.println("</html>");
    }

    // Method to escape HTML characters to prevent XSS attacks
    private String escapeHtml(String input) {
        return input != null ? input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#39;") : "";
    }
}
``

